service-worker-lifecycle.example:
self.addEventListener('activate', event => {
  event.waitUntil(caches.keys().then(keys => Promise.all(keys.filter(k => k !== 'v1').map(k => caches.delete(k)))))
})

caching-strategies.example:
event.respondWith(caches.open('v1').then(cache => {
  return cache.match(event.request).then(cached => {
    const fetchPromise = fetch(event.request).then(networkResponse => {
      cache.put(event.request, networkResponse.clone());
      return networkResponse;
    });
    return cached || fetchPromise;
  });
}))

offline-capabilities.example:
navigator.serviceWorker.ready.then(reg => reg.sync.register('sync-queue'))
// Di service worker:
self.addEventListener('sync', event => { if (event.tag === 'sync-queue') { event.waitUntil(processQueue()) } })

navigator.serviceWorker.ready.then(reg => reg.periodicSync.register('update-feed', { minInterval: 60 * 60 * 1000 }))
// Di service worker:
self.addEventListener('periodicsync', event => { if (event.tag === 'update-feed') { event.waitUntil(fetchNewContent()) } })

notifications-push.example:
self.addEventListener('push', event => {
  const data = event.data.json()
  event.waitUntil(self.registration.showNotification(data.title, { body: data.body, icon: '/icon.png' }))
})
